const crypto = require('crypto');

function hashPassword(password) {
  const salt = crypto.randomBytes(16).toString('hex');
  const key = crypto.createHash('sha256').update(salt + password).digest('hex');
  return { salt, key };
}

function verifyPassword(storedKey, providedKey, storedSalt) {
  const newKey = crypto.createHash('sha256').update(storedSalt + providedKey).digest('hex');
  return newKey === storedKey;
}

// Example usage:
const password = 'mysecretpassword';
const hashedPassword = hashPassword(password);
console.log(hashedPassword);

const isValid = verifyPassword(hashedPassword.key, password, hashedPassword.salt);
